const basePriceByItemType: Record<string, number> = {
  sword: 115,
  amulet: 71,
  staff: 93,
  potion: 49,
  rune: 33,
};

const THREE_ALIKE_BUNDLE_PRICE = 71;

const isThreeAlikeBundle = (items: any[]): boolean =>
  items.length === 3 && items.every((i) => i.type === items[0].type);

const quotePremium = (items: any[]): number => {
  if (isThreeAlikeBundle(items)) return THREE_ALIKE_BUNDLE_PRICE;
  return basePriceByItemType[items[0].type];
};

export const runScenario = (scenario: any): unknown => {
  const items = scenario.steps[0].items;
  return { results: [{ premium: quotePremium(items) }] };
};
